impl InlinableExpression {
    fn to_expression(&self, modules: &im::HashMap<EcoString, ModuleInterface>) -> TypedExpr {
        match self {
            InlinableExpression::Case {
                subjects,
                clauses,
                compiled_case,
                type_,
            } => TypedExpr::Case {
                location: BLANK_LOCATION,
                type_: type_.to_type(),
                subjects: subjects
                    .iter()
                    .map(|subject| subject.to_expression(modules))
                    .collect(),
                clauses: clauses
                    .iter()
                    .map(|clause| clause.to_typed_clause(modules))
                    .collect(),
                compiled_case: compiled_case.as_ref().clone(),
            },
            InlinableExpression::Variable {
                name,
                constructor,
                type_,
            } => TypedExpr::Var {
                location: BLANK_LOCATION,
                constructor: constructor.to_value_constructor(type_.to_type()),
                name: name.clone(),
            },
            InlinableExpression::Call {
                function,
                arguments,
                type_,
            } => TypedExpr::Call {
                location: BLANK_LOCATION,
                type_: type_.to_type(),
                fun: Box::new(function.to_expression(modules)),
                arguments: arguments
                    .iter()
                    .map(|argument| argument.to_call_arg(|expr| expr.to_expression(modules)))
                    .collect(),
            },
            InlinableExpression::ConstantReference { name, module, type_ } => {
                // Look up the constant from the module interface to get the actual literal value
                match module {
                    Some(module_name) => {
                        // Look up the module
                        let module_interface = modules.get(module_name);
                        let constant_literal = module_interface
                            .and_then(|m| m.values.get(name))
                            .and_then(|value| match &value.variant {
                                ValueConstructorVariant::ModuleConstant { literal, .. } => {
                                    Some(literal.clone())
                                }
                                _ => None,
                            });

                        TypedExpr::ModuleSelect {
                            location: BLANK_LOCATION,
                            type_: type_.to_type(),
                            label: name.clone(),
                            module_name: module_name.clone(),
                            module_alias: module_name.clone(),
                            constructor: ModuleValueConstructor::Constant {
                                documentation: None,
                                location: BLANK_LOCATION,
                                literal: constant_literal.unwrap_or_else(|| ast::Constant::Invalid {
                                    location: BLANK_LOCATION,
                                    type_: type_.to_type(),
                                }),
                                implementations: Implementations::supporting_all(),
                            },
                        }
                    }
                    None => {
                        // Local constant - we can't look it up, so we create an Invalid placeholder
                        // This should rarely happen as local constants are usually defined inline
                        TypedExpr::Var {
                            location: BLANK_LOCATION,
                            constructor: ValueConstructor {
                                publicity: Publicity::Private,
                                deprecation: Deprecation::NotDeprecated,
                                variant: ValueConstructorVariant::LocalConstant {
                                    literal: ast::Constant::Invalid {
                                        location: BLANK_LOCATION,
                                        type_: type_.to_type(),
                                    },
                                },
                                type_: type_.to_type(),
                            },
                            name: name.clone(),
                        }
                    }
                }
            }
        }
    }
}

